%dw 2.0
output application/json
---
{
  "error": "authentication_required",
  "message": "Please connect your bank account to view real balance data",
  "oauthError": payload.error default "no_tokens",
  "oauthDescription": payload.error_description default "No OAuth tokens available",
  "fallbackData": {
    "totalBalance": {
      "amount": 0.00,
      "currency": "CAD",
      "lastUpdated": now() as String {format: "yyyy-MM-dd'T'HH:mm:ss'Z'"}
    },
    "accountBreakdown": [],
    "note": "Connect your bank account to see real data"
  },
  "oauthStatus": {
    "authenticated": false,
    "tokenPresent": false,
    "dataSource": "Mock/Fallback Data"
  }
}
